504 /// the result is larger than the maximum representable value of type T.
505 template <typename T>
506 std::enable_if_t<std::is_unsigned_v<T>, T>
507 SaturatingMultiply(T X, T Y, bool *ResultOverflowed = nullptr) {
508   bool Dummy;
